/* ============================================================
   RÉINITIALISATION DES CATÉGORIES SODIV BUREAU
   Génère 15 catégories principales + sous + sous-sous
   ============================================================ */

SET XACT_ABORT ON;
BEGIN TRANSACTION;

-- 1) Catégorie temporaire pour préserver les produits existants
IF NOT EXISTS (SELECT 1 FROM Categories WHERE Nom = N'À reclasser')
BEGIN
    VALUES (N'À reclasser', N'a-reclasser', N'fa-question-circle', 1, NULL);
END;

DECLARE @TempId INT = (SELECT Id FROM Categories WHERE Nom = N'À reclasser');

-- 2) Déplacer tous les produits vers la catégorie temporaire
UPDATE Produits SET CategorieId = @TempId WHERE CategorieId <> @TempId;

-- 3) Supprimer toutes les autres catégories
DELETE FROM Categories WHERE Id <> @TempId;

-- 4) Insertion des nouvelles catégories niveau par niveau

-- ════════ NIVEAU 0 (catégories principales) ════════

-- ════════ NIVEAU 1 (sous-catégories) ════════

-- ════════ NIVEAU 2 (sous-sous-catégories) ════════



COMMIT TRANSACTION;

-- TOTAL : 15 principales + 82 sous + 141 sous-sous
-- + 1 'À reclasser' qui contient temporairement tes anciens produits
PRINT N'Catégories réinitialisées avec succès.';